import{_ as e,c as o,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Avanzado: Flujos de Trabajo de IA | oh-my-opencode","description":"Domina la orquestación avanzada de flujos de trabajo de IA en oh-my-opencode. Aprende sobre equipos de agentes, tareas paralelas, sistema de Categorías/Habilidades, ganchos de ciclo de vida y personalización profunda para construir sistemas de desarrollo eficientes potenciados por IA.","frontmatter":{"title":"Avanzado: Flujos de Trabajo de IA | oh-my-opencode","sidebarTitle":"Trabaja como un Equipo","subtitle":"Avanzado: Flujos de Trabajo de IA","description":"Domina la orquestación avanzada de flujos de trabajo de IA en oh-my-opencode. Aprende sobre equipos de agentes, tareas paralelas, sistema de Categorías/Habilidades, ganchos de ciclo de vida y personalización profunda para construir sistemas de desarrollo eficientes potenciados por IA.","order":60},"headers":[],"relativePath":"es/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"es/code-yeongyu/oh-my-opencode/advanced/index.md"}'),s={name:"es/code-yeongyu/oh-my-opencode/advanced/index.md"};function d(r,a,t,l,c,u){return i(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="avanzado" tabindex="-1">Avanzado <a class="header-anchor" href="#avanzado" aria-label="Permalink to &quot;Avanzado&quot;">​</a></h1><p>Este capítulo profundiza en las características avanzadas de oh-my-opencode: equipos profesionales de agentes de IA, tareas paralelas en segundo plano, sistema de Categorías y Habilidades, ganchos de ciclo de vida y más. Dominar estas capacidades te permitirá orquestar flujos de trabajo de IA como gestionar un equipo real, logrando una experiencia de desarrollo más eficiente.</p><h2 id="contenido-del-capitulo" tabindex="-1">Contenido del Capítulo <a class="header-anchor" href="#contenido-del-capitulo" aria-label="Permalink to &quot;Contenido del Capítulo&quot;">​</a></h2><div class="grid-cards"><h3 id="equipos-de-agentes-de-ia-descripcion-general-de-10-expertos" tabindex="-1"><a href="./ai-agents-overview/">Equipos de Agentes de IA: Descripción General de 10 Expertos</a> <a class="header-anchor" href="#equipos-de-agentes-de-ia-descripcion-general-de-10-expertos" aria-label="Permalink to &quot;[Equipos de Agentes de IA: Descripción General de 10 Expertos](./ai-agents-overview/)&quot;">​</a></h3><p>Introducción completa a la funcionalidad, casos de uso y métodos de llamada de 10 agentes integrados. Aprende a seleccionar el agente adecuado según el tipo de tarea, permitiendo una colaboración eficiente del equipo, ejecución paralela de tareas y análisis profundo de código.</p><h3 id="planificacion-prometheus-recopilacion-de-requisitos-basada-en-entrevistas" tabindex="-1"><a href="./prometheus-planning/">Planificación Prometheus: Recopilación de Requisitos Basada en Entrevistas</a> <a class="header-anchor" href="#planificacion-prometheus-recopilacion-de-requisitos-basada-en-entrevistas" aria-label="Permalink to &quot;[Planificación Prometheus: Recopilación de Requisitos Basada en Entrevistas](./prometheus-planning/)&quot;">​</a></h3><p>Clarifica los requisitos y genera planes de trabajo a través del modo de entrevista. Prometheus continuará haciendo preguntas hasta que los requisitos sean claros y consulta automáticamente a Oracle, Metis y Momus para verificar la calidad del plan.</p><h3 id="tareas-paralelas-en-segundo-plano-trabaja-como-un-equipo" tabindex="-1"><a href="./background-tasks/">Tareas Paralelas en Segundo Plano: Trabaja como un Equipo</a> <a class="header-anchor" href="#tareas-paralelas-en-segundo-plano-trabaja-como-un-equipo" aria-label="Permalink to &quot;[Tareas Paralelas en Segundo Plano: Trabaja como un Equipo](./background-tasks/)&quot;">​</a></h3><p>Explicación profunda del uso del sistema de gestión de agentes en segundo plano. Aprende el control de concurrencia, sondeo de tareas y recuperación de resultados, permitiendo que múltiples agentes de IA manejen diferentes tareas simultáneamente, mejorando drásticamente la eficiencia del trabajo.</p><h3 id="lsp-y-ast-grep-herramientas-de-refactorizacion-de-codigo" tabindex="-1"><a href="./lsp-ast-tools/">LSP y AST-Grep: Herramientas de Refactorización de Código</a> <a class="header-anchor" href="#lsp-y-ast-grep-herramientas-de-refactorizacion-de-codigo" aria-label="Permalink to &quot;[LSP y AST-Grep: Herramientas de Refactorización de Código](./lsp-ast-tools/)&quot;">​</a></h3><p>Introducción al uso de herramientas LSP y herramientas AST-Grep. Demuestra cómo implementar análisis y operaciones de código a nivel de IDE, incluyendo navegación de símbolos, búsqueda de referencias y búsqueda estructurada de código.</p><h3 id="categorias-y-habilidades-composicion-dinamica-de-agentes" tabindex="-1"><a href="./categories-skills/">Categorías y Habilidades: Composición Dinámica de Agentes</a> <a class="header-anchor" href="#categorias-y-habilidades-composicion-dinamica-de-agentes" aria-label="Permalink to &quot;[Categorías y Habilidades: Composición Dinámica de Agentes](./categories-skills/)&quot;">​</a></h3><p>Aprende a usar el sistema de Categorías y Habilidades para crear sub-agentes especializados. Implementa una composición flexible de agentes, asignando dinámicamente modelos, herramientas y habilidades según los requisitos de la tarea.</p><h3 id="habilidades-integradas-automatizacion-del-navegador-y-experto-en-git" tabindex="-1"><a href="./builtin-skills/">Habilidades Integradas: Automatización del Navegador y Experto en Git</a> <a class="header-anchor" href="#habilidades-integradas-automatizacion-del-navegador-y-experto-en-git" aria-label="Permalink to &quot;[Habilidades Integradas: Automatización del Navegador y Experto en Git](./builtin-skills/)&quot;">​</a></h3><p>Introducción detallada a los casos de uso y mejores prácticas de tres Habilidades integradas (playwright, frontend-ui-ux, git-master). Accede rápidamente a capacidades profesionales como automatización del navegador, diseño de interfaz de usuario frontend y operaciones de Git.</p><h3 id="ganchos-de-ciclo-de-vida-automatizacion-de-contexto-y-control-de-calidad" tabindex="-1"><a href="./lifecycle-hooks/">Ganchos de Ciclo de Vida: Automatización de Contexto y Control de Calidad</a> <a class="header-anchor" href="#ganchos-de-ciclo-de-vida-automatizacion-de-contexto-y-control-de-calidad" aria-label="Permalink to &quot;[Ganchos de Ciclo de Vida: Automatización de Contexto y Control de Calidad](./lifecycle-hooks/)&quot;">​</a></h3><p>Introducción al uso de 32 ganchos de ciclo de vida. Entiende cómo automatizar la inyección de contexto, recuperación de errores y control de calidad, construyendo un sistema completo de automatización de flujos de trabajo de IA.</p><h3 id="comandos-slash-flujos-de-trabajo-preestablecidos" tabindex="-1"><a href="./slash-commands/">Comandos Slash: Flujos de Trabajo Preestablecidos</a> <a class="header-anchor" href="#comandos-slash-flujos-de-trabajo-preestablecidos" aria-label="Permalink to &quot;[Comandos Slash: Flujos de Trabajo Preestablecidos](./slash-commands/)&quot;">​</a></h3><p>Introducción al uso de 6 comandos slash integrados. Incluyendo /ralph-loop (bucle de corrección rápida), /refactor (refactorización de código), /start-work (inicio de ejecución del proyecto) y otros flujos de trabajo comunes.</p><h3 id="personalizacion-profunda-de-configuracion-gestion-de-agentes-y-permisos" tabindex="-1"><a href="./advanced-configuration/">Personalización Profunda de Configuración: Gestión de Agentes y Permisos</a> <a class="header-anchor" href="#personalizacion-profunda-de-configuracion-gestion-de-agentes-y-permisos" aria-label="Permalink to &quot;[Personalización Profunda de Configuración: Gestión de Agentes y Permisos](./advanced-configuration/)&quot;">​</a></h3><p>Enseña a los usuarios la personalización profunda de la configuración de agentes, configuración de permisos, anulaciones de modelos y modificaciones de prompts. Domina capacidades completas de configuración, creando flujos de trabajo de IA alineados con los estándares del equipo.</p></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Paso 1                   Paso 2                      Paso 3                           Paso 4                  │</span></span>
<span class="line"><span>│  Entender Agentes de IA →   Dominar Planificación →   Aprender Composición        →   Personalización        │</span></span>
<span class="line"><span>│  (Conceptos Básicos)          y Tareas Paralelas         Dinámica de Agentes         Profunda y Automatización │</span></span>
<span class="line"><span>│                                                           (Uso Avanzado)            (Nivel Experto)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Secuencia Recomendada</strong>:</p><ol><li><strong>Comienza con Equipos de Agentes de IA</strong>: Entiende las responsabilidades y casos de uso de 10 agentes—esta es la piedra angular para entender todo el sistema.</li><li><strong>Luego Aprende Planificación y Tareas Paralelas</strong>: Domina la planificación Prometheus y el sistema de tareas en segundo plano—este es el núcleo de la colaboración eficiente.</li><li><strong>A continuación Aprende Composición Dinámica de Agentes</strong>: Aprende Categorías y Habilidades para lograr una especialización flexible de agentes.</li><li><strong>Finalmente Aprende Personalización Profunda</strong>: Domina los ganchos de ciclo de vida, comandos slash y personalización de configuración para construir flujos de trabajo completos.</li></ol><p><strong>Rutas Avanzadas</strong>:</p><ul><li>Si tu objetivo es <strong>inicio rápido</strong>: Enfócate en &quot;Equipos de Agentes de IA&quot; y &quot;Comandos Slash&quot;</li><li>Si tu objetivo es <strong>colaboración en equipo</strong>: Profundiza en &quot;Planificación Prometheus&quot; y &quot;Tareas Paralelas en Segundo Plano&quot;</li><li>Si tu objetivo es <strong>automatización de flujos de trabajo</strong>: Aprende &quot;Ganchos de Ciclo de Vida&quot; y &quot;Personalización Profunda de Configuración&quot;</li></ul><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de Comenzar</p><p>Este capítulo asume que has completado:</p><ul><li>✅ <a href="./../start/installation/">Instalación Rápida y Configuración</a>: Instalado oh-my-opencode y configurado al menos un Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">Primera Mirada a Sisyphus: Orquestador Principal</a>: Entendido los mecanismos básicos de llamada y delegación de agentes</li><li>✅ <a href="./../platforms/provider-setup/">Configuración de Provider: Claude, OpenAI, Gemini</a>: Configurado al menos un AI Provider</li></ul></div><h2 id="proximos-pasos" tabindex="-1">Próximos Pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos Pasos&quot;">​</a></h2><p>Después de completar este capítulo, recomendamos continuar con:</p><ul><li><strong><a href="./../faq/troubleshooting/">Diagnóstico de Configuración y Solución de Problemas</a></strong>: Localiza y resuelve rápidamente problemas cuando surjan.</li><li><strong><a href="./../appendix/configuration-reference/">Referencia de Configuración</a></strong>: Consulta el esquema completo del archivo de configuración y entiende todas las opciones de configuración.</li><li><strong><a href="./../appendix/claude-code-compatibility/">Compatibilidad con Claude Code</a></strong>: Aprende cómo migrar flujos de trabajo existentes de Claude Code a oh-my-opencode.</li></ul>`,15)])])}const g=e(s,[["render",d]]);export{m as __pageData,g as default};
